wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(118788788995872463547)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'New'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
'',
'    :P3_BILET_ID := :P4_BILET_ID;',
'',
'',
'    SELECT ',
'        s.tytul_spektaklu,',
'  ',
'        TO_CHAR(p.data_przedstawienia, ''DD.MM.YYYY'') || '' '' || TO_CHAR(p.godzina_przedstawienia, ''HH24:MI''),',
'        sl.numer_sali,',
'        TO_CHAR(b.koszt_biletu, ''999G990D00'') ',
'    INTO ',
'        :P3_TYTUL,          ',
'        :P3_DATA_GODZINA,  ',
'        :P3_SALA,           ',
'        :P3_CENA            ',
'    FROM bilety b',
'    JOIN przedstawienie p ON b.przedstawienie_id_przedstawienia = p.id_przedstawienia',
'    JOIN spektakl s ON p.spektakl_id_spektaklu = s.id_spektaklu',
'    JOIN sala sl ON p.sala_id_sali = sl.id_sali',
'',
'    WHERE b.id_biletu = :P4_BILET_ID;',
'',
'EXCEPTION',
'    WHEN NO_DATA_FOUND THEN',
'',
unistr('        :P3_TYTUL := ''B\0142\0105d pobierania danych'';'),
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>118788788995872463547
);
end;
