'    p_klient_id     => :P4_KLIENT_ID,',
'    p_znizka_nazwa  => :P4_ZNIZKA,',
'    p_typ_miejsca   => :P4_TYP_MIEJSCA,',
'    p_platnosc      => :P4_PLATNOSC,',
'    p_koszt_out     => v_koszt,',
'    p_status        => v_stat,',
'    p_msg           => v_msg',
'  );',
'',
'  IF v_stat = 0 THEN',
'      apex_application.g_print_success_message := v_msg;',
'  ELSIF v_stat = 1 THEN',
'      apex_error.add_error(',
'          p_message => v_msg,',
