,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    to_char(p.godzina_przedstawienia, ''HH24:MI'') as godzina,',
'    s.tytul_spektaklu,',
'    sl.numer_sali,',
'',
'    NVL(pkg_raporty.oblicz_przychod(p.id_przedstawienia), 0) || '' PLN'' as przychod,',
'',
'    NVL(sc.krotki_opis_scenerii, ''Brak scenerii'') as sceneria',
'FROM przedstawienie p',
'JOIN spektakl s ON p.spektakl_id_spektaklu = s.id_spektaklu',
'JOIN sala sl ON p.sala_id_sali = sl.id_sali',
'LEFT JOIN sceneria sc ON p.sceneria_id_scenerii = sc.id_scenerii ',
'',
'WHERE trunc(p.data_przedstawienia) = trunc(TO_DATE(:P11_DATA_RAPORTU, ''YYYY-MM-DD''))',
'ORDER BY p.godzina_przedstawienia'))
