,p_plug_name=>unistr('Grafik Pracownik\00F3w')
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    p.ID_przedstawienia, ',
'    pt.imie_pracownika || '' '' || pt.nazwisko_pracownika as pracownik,',
'    z.nazwa_zawodu as rola,',
'    s.tytul_spektaklu,',
'    TO_CHAR(p.data_przedstawienia, ''DD.MM.YYYY'') || '' | '' || TO_CHAR(p.godzina_przedstawienia, ''HH24:MI'') as termin,',
'    sl.numer_sali',
'FROM PRZEDSTAWIENIE_PRACOWNIK pp',
'JOIN PRACOWNICY_TEATRU pt ON pp.PRACOWNICY_TEATRU_ID_pracownika = pt.ID_pracownika',
'JOIN PRZEDSTAWIENIE p ON pp.PRZEDSTAWIENIE_ID_przedstawienia = p.ID_przedstawienia',
'JOIN SPEKTAKL s ON p.SPEKTAKL_id_spektaklu = s.ID_spektaklu',
'JOIN ZAWOD z ON pp.ID_zawodu = z.ID_zawodu',
'JOIN SALA sl ON p.SALA_id_sali = sl.ID_sali',
'ORDER BY p.data_przedstawienia DESC, pt.nazwisko_pracownika'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>unistr('Grafik Pracownik\00F3w')
);
