'INSERT INTO PRZEDSTAWIENIE_PRACOWNIK (ID_przedstawienie_pracownik, PRZEDSTAWIENIE_ID_przedstawienia, PRACOWNICY_TEATRU_ID_pracownika, ID_zawodu) VALUES (2305, 79, 40, 1);',
'INSERT INTO PRZEDSTAWIENIE_PRACOWNIK (ID_przedstawienie_pracownik, PRZEDSTAWIENIE_ID_przedstawienia, PRACOWNICY_TEATRU_ID_pracownika, ID_zawodu) VALUES (2306, 80, 44, 2);',
